import sys

class Solution:
    def floorAndCeil(self, nums: list[int], target: int) -> list[int]:
        left, right = 0, len(nums) - 1
        floor, ceil = -1, -1
        while left <= right:
            mid = (left + right) // 2
            if nums[mid] == target:
                floor, ceil = target, target
                break
            elif nums[mid] < target:
                floor = nums[mid]
                left = mid + 1
            else:
                ceil = nums[mid]
                right = mid - 1
        if floor == -1:
            if nums and nums[0] >= target:
                ceil = nums[0]
            else:
                ceil = -1
        if ceil == -1:
            if nums and nums[-1] <= target:
                floor = nums[-1]
            else:
                floor = -1
        return [floor, ceil]

