#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> floorAndCeil(vector<int>& nums, int target) {
        int left = 0, right = nums.size() - 1;
        int floor = -1, ceil = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] == target) {
                floor = target;
                ceil = target;
                break;
            } else if (nums[mid] < target) {
                floor = nums[mid];
                left = mid + 1;
            } else {
                ceil = nums[mid];
                right = mid - 1;
            }
        }
        if (floor == -1) {
            if (!nums.empty() && nums[0] >= target) {
                ceil = nums[0];
            } else {
                ceil = -1;
            }
        }
        if (ceil == -1) {
            if (!nums.empty() && nums.back() <= target) {
                floor = nums.back();
            } else {
                floor = -1;
            }
        }
        return {floor, ceil};
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int target;
    if (!(cin >> target)) return 0;
    Solution sol;
    vector<int> ans = sol.floorAndCeil(nums, target);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
